"""UxPrototypeResult — immutable domain model for generated UX prototypes."""

from __future__ import annotations

from enum import Enum

from pydantic import BaseModel, Field


class ScreenState(str, Enum):
    """Mandatory states for each prototype screen."""

    LOADING = "loading"
    EMPTY = "empty"
    DATA = "data"
    ERROR = "error"


class PrototypeScreen(BaseModel, frozen=True):
    """A single prototype screen generated by SKILL-UX-01."""

    screen_id: str = Field(description="Unique screen identifier (e.g. 'transferencia-form').")
    title: str = Field(description="Human-readable screen title.")
    html_content: str = Field(description="Full self-contained HTML for this screen.")
    states: list[ScreenState] = Field(
        default_factory=list,
        description="Screen states represented in this prototype.",
    )
    navigation_flows: list[str] = Field(
        default_factory=list,
        description="Target screen_ids this screen can navigate to.",
    )


class UxPrototypeResult(BaseModel, frozen=True):
    """Immutable result of prototype generation.

    Contains one or more HTML prototype screens with metadata
    for auditing and version tracking.
    """

    issue_number: int = Field(description="GitHub Issue number.")
    screens: list[PrototypeScreen] = Field(
        default_factory=list,
        description="Generated prototype screens.",
    )
    design_tokens_used: list[str] = Field(
        default_factory=list,
        description="CSS custom property names referenced in the prototypes.",
    )
    blueprint_hash: str = Field(
        default="",
        description="SHA-256 hash of the blueprint file used as context.",
    )
    model_used: str = Field(
        default="",
        description="LLM model identifier used for generation.",
    )
    prompt_version: str = Field(
        default="v1",
        description="Version tag of the prompt template used.",
    )

    @property
    def screen_count(self) -> int:
        """Total number of generated screens."""
        return len(self.screens)

    @property
    def all_states_covered(self) -> bool:
        """Check if every screen covers all 4 mandatory states."""
        required = set(ScreenState)
        return all(set(screen.states) >= required for screen in self.screens)
